// Reject anything without explicit, owner-confirmed consent.
const body = $json.body ?? $json;
const consent = body.consent ?? {};
if (consent.granted !== true || consent.subject_confirmed_owner !== true) {
  throw new Error('Consent required: the subject must confirm ownership and grant consent.');
}
const numero = String(body.documento_numero ?? '').replace(/\D/g, '');
if (!/^\d{7,8}$/.test(numero)) throw new Error('Invalid document number.');
const sexo = String(body.sexo ?? '').toUpperCase();
if (!['F', 'M', 'X'].includes(sexo)) throw new Error('Invalid sexo (F|M|X).');

const salt = $env.APP_SALT;
if (!salt) throw new Error('APP_SALT environment variable is not configured.');
const { createHash } = require('crypto');
const subject_ref = createHash('sha256').update(numero + sexo + salt).digest('hex');

return [{ json: {
  numero, sexo, subject_ref,
  purpose: body.purpose ?? 'Autoverificación de identidad solicitada por el propio titular.',
  terms_version: consent.terms_version ?? 'unversioned',
  request_key: $execution.id,
  mode: $env.IDENTITY_MODE === 'live' ? 'live' : 'mock',
} }];

parameters.query:
INSERT INTO identity.consent_records (subject_ref, purpose, terms_version, channel)
VALUES ($1, $2, $3, 'web')
RETURNING id;

