// Synthetic provider. Returns data ONLY for the configured test DNI; any other
// document yields not_found. This makes the demo unusable against real people.
const TEST = { numero: '30123456', sexo: 'F' };
const input = $('Consent gate + subject_ref').item.json;
if (input.numero !== TEST.numero || input.sexo !== TEST.sexo) {
  return [{ json: { status: 'not_found', subject: null } }];
}
return [{ json: { status: 'verified', subject: {
  documento: { tipo: 'DNI', numero: '30123456', ejemplar: 'A' },
  sexo: 'F', nombres: 'Ada Ejemplo', apellidos: 'Demostración',
  cuil: '27-30123456-4', fecha_nacimiento: '1983-04-15', nacionalidad: 'Argentina',
  fallecido: false,
  domicilio: { calle: 'Av. de la Demostración', numero: '1234', piso: '3 B',
    ciudad: 'Rosario', provincia: 'Santa Fe', codigo_postal: 'S2000DXX',
    lon: -60.6505, lat: -32.9468 },
  foto: { kind: 'placeholder', mime: 'image/svg+xml', uri: '/public/avatar-placeholder.svg',
    note: 'Imagen generada. En modo demo no se expone ninguna fotografía real.' },
} }];

// Assemble an identity-verification document (see the contract) and prepare the
// minimized profile row. Retention defaults to 180 days unless configured.
const gate = $('Consent gate + subject_ref').item.json;
const prov = $json;
const now = new Date();
const retentionDays = Number($env.IDENTITY_RETENTION_DAYS ?? 180);
const retentionUntil = new Date(now.getTime() + retentionDays * 86400000);
const doc = {
  contract: 'identity-verification', contract_version: '1.0.0',
  request_id: gate.request_key, generated_at: now.toISOString().replace(/\.\d{3}Z$/, 'Z'),
  mode: gate.mode,
  consent: { granted: true, subject_confirmed_owner: true, purpose: gate.purpose,
    legal_basis: 'Consentimiento del titular (Ley 25.326, arts. 5 y 6).',
    terms_version: gate.terms_version, consented_at: now.toISOString().replace(/\.\d{3}Z$/, 'Z'),
    expires_at: retentionUntil.toISOString().replace(/\.\d{3}Z$/, 'Z') },
  verification: { status: prov.status, provider: gate.mode === 'live' ? 'renaper' : 'renaper-mock',
    provider_label: gate.mode === 'live' ? 'RENAPER' : 'RENAPER (proveedor simulado)',
    verified_at: prov.status === 'verified' ? now.toISOString().replace(/\.\d{3}Z$/, 'Z') : null,
    request_key: gate.request_key, match_score: prov.status === 'verified' ? 1.0 : null, error: null },
  subject: prov.subject ?? undefined,
  source_status: [{ source_id: 'renaper', name: 'RENAPER — Registro Nacional de las Personas',
    url: 'https://www.argentina.gob.ar/renaper', status: gate.mode === 'live' ? 'ok' : 'mock',
    mode: gate.mode, last_success_at: now.toISOString().replace(/\.\d{3}Z$/, 'Z'), last_error: null }],
  governance: { data_subject_rights: 'Acceso, rectificación, supresión y oposición (ARCO).',
    rights_contact: $env.PRIVACY_CONTACT ?? 'privacidad@example.org',
    retention_until: retentionUntil.toISOString().replace(/\.\d{3}Z$/, 'Z'), stored_fields_minimized: true },
};
if (gate.mode === 'mock') doc.demo_test_subject = { documento_numero: '30123456', sexo: 'F' };
return [{ json: { doc, subject_ref: gate.subject_ref, retention_until: doc.governance.retention_until,
  status: prov.status, request_key: gate.request_key,
  payload: JSON.stringify(prov.subject ?? {}), photo_kind: prov.subject?.foto?.kind ?? 'placeholder',
  photo_ref: prov.subject?.foto?.uri ?? null } }];
